Drupal.behaviors.selectAutocomplete={attach(e){const t=e.querySelector("select#edit-major-works-neighbourhood");t&&accessibleAutocomplete.enhanceSelectElement({selectElement:t,onConfirm:e=>{const o=t.closest("form");for(let o=0;o<t.options.length;o+=1)if(t.options[o].text===e){t.selectedIndex=o;break}o.submit()}})}};